// Compute severity + headroom + top providers from the usage payload.
// Input  : $json from HTTP node — { mtd_mb, hard_stop_threshold_mb, by_provider, ... }
// Output : flat object consumed by the Switch + Telegram nodes downstream.

const data = $json || {};
const mtd_mb = Number(data.mtd_mb ?? 0);
const hard_stop_threshold_mb = Number(data.hard_stop_threshold_mb ?? 950);
const headroom_mb = Math.max(0, Math.round((hard_stop_threshold_mb - mtd_mb) * 100) / 100);
const pct_used = hard_stop_threshold_mb > 0
  ? Math.round((mtd_mb / hard_stop_threshold_mb) * 1000) / 10
  : 0;

let severity = 'ok';
if (mtd_mb >= 800) severity = 'hard_stop';
else if (mtd_mb >= 500) severity = 'critical';
else if (mtd_mb >= 300) severity = 'warning';

// by_provider can be { provider: {bytes, requests, ...} } or empty.
const providers = data.by_provider && typeof data.by_provider === 'object'
  ? Object.entries(data.by_provider)
  : [];
const top_providers = providers
  .map(([name, stats]) => ({
    name,
    bytes: Number((stats && stats.bytes) ?? 0),
    mb: Math.round(((Number((stats && stats.bytes) ?? 0)) / (1024 * 1024)) * 100) / 100,
    requests: Number((stats && stats.requests) ?? 0),
  }))
  .sort((a, b) => b.bytes - a.bytes)
  .slice(0, 3);

const top_providers_md = top_providers.length
  ? top_providers
      .map((p, i) => `${i + 1}. \`${p.name}\` — ${p.mb} MB (${p.requests} req)`)
      .join('\n')
  : '_(aucun provider remonté)_';

const proxy_disabled_env = data.proxy_disabled_env === true || data.proxy_disabled_env === 'true';

return {
  json: {
    severity,
    mtd_mb,
    hard_stop_threshold_mb,
    headroom_mb,
    pct_used,
    top_providers,
    top_providers_md,
    proxy_disabled_env,
    total_requests_mtd: Number(data.total_requests_mtd ?? 0),
    fetched_at: new Date().toISOString(),
  },
};
